head.script:
/**
 * 화 면 명 : 감가상각처리
 * 메뉴경로 : 회계/재무회계/고정자산/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/fixedaset/fi_302_01_01b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-11-18
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항 : 
 *    1. 그리드ID.setNoResultMessageVisible(false) 설정해줘야 그리드에 데이터없음 안보임
 *    2. ☏ $c.gus.cfJobCloseYN 공통함수 없음
 *    ☞ 2025-12-22 공통개발됨(udc_comChkRes)
 * 수정이력 :
 *    - 2025-11-18      배기원    최초작성
 */
//hidden 값
scwin.txtCoClsCd    = "";      //회사구분코드(hidden, 회사팝업호출 시)

//로그인 정보
scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;

scwin.isClose  = "";    //마감체크(tobe 추가)
scwin.initJson = {};    //초기세팅값(TOBE)
scwin.first = 0;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.first = 0;
    /**
     * TODO : 임시로 회사코드 초기값 가지고 있기 위해 처리
     * 로드 시 마지막으로 처리되는 로직
     */
    const codeOptions = [
        { grpCd: "EQ055", compID: "" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
    scwin.initJson = dma_search.getJSON();
};
/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_master.setNoResultMessageVisible(false);
    ds_master.reform();
    ds_master.removeAll();
    totalRows.setValue("0");
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    // scwin.f_Header();
    // scwin.f_FieldClear();
    // scwin.f_setCompanyInfo();
    scwin.setInit();
    scwin.f_SetSrchDefault();
    scwin.f_setCompanyInfo();
};


/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ed_coCd, ed_coNm, ica_closeYm]);
    //dma_search.setJSON(scwin.initJson);
    scwin.f_SetSrchDefault();
};
/**
 * 자회사 회계 시스템 추가에 따른 설정 
 */
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를 '동부 EXPRESS'로 Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};


/**
 * 조회 데이터셋 헤더 생성
 * TOBE 사용안함
 */
// scwin.f_Header = function() {
//     var GAUCE_DATASET_HEADER = "closeYm:STRING(6)" // 마감년월
//         + ",coCd:STRING(3)" // 회사코드
//         + ",coClsCd:STRING(1)"; // 회사구분코드
//     ds_search.SetDataHeader(GAUCE_DATASET_HEADER);
//     ds_search.insertRow();
// };


/**
 * 조회 기본값 설정
 */
scwin.f_SetSrchDefault = function() {
    ica_closeYm.focus();
};


/**
 * 조회
 */
scwin.f_Retrieve = async function () {
    let ret;
    ret = await $c.gus.cfValidate([tbl_search]);
    if(!ret) {
        return false;
    }
    // var condition = "?coCd" + ed_coCd.getValue().trim() + "&closeYm" + ica_closeYm.getValue().trim() + "&closeDd00&mgntNo0";
    // condition += "&wrkNo=scwin.ACConstants.CLOSE_DEPRECIATION";

    // ds_master.DataID = "/cm.bc.comnmgnt.closemgnt.RetrieveCloseLogListCMD.do" + condition;
    // ds_master.undoAll();
    scwin.setInit();
    dma_search.set("coClsCd", scwin.txtCoClsCd);
    dma_search.set("closeDd", "00");
    dma_search.set("mgntNo" , "0");
    dma_search.set("wrkNo"  , ACConstants.CLOSE_DEPRECIATION);

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_master.setNoResultMessageVisible(true);
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다

        } else {
            //조회된 결과 정렬(asis:<param name=SortExpr 참조)
            ds_master.sort("opntAcctCd", 0);
            gr_master.setFocusedCell(0, 0);
        }
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * 감가상각처리
 */
scwin.f_DeprProc = async function () {
    let ret;
    ret = await $c.gus.cfValidate([tbl_search]);
    if(!ret) {
        return false;
    }

    // 마감체크
    ret = await scwin.f_JobCloseYN();
    if(!ret) {
        return false;
    }

    // ret = await $c.win.confirm("감가상각내역" +MSG_CM_CRM_009);
    ret = await $c.win.confirm("감가상각내역을(를) 생성하시겠습니까?");
    if(ret) {
        sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_012,["감가상각내역"]);
        scwin.f_Retrieve(); 
    }
};

scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * 마감체크
 */
scwin.f_JobCloseYN = async function () {
    /**
     * @param  : pReqKind  : 마감요청구분("PRE":선행마감체크, "CUR":작업마감체크)
     *           pCloseYM  : 마감년월(YYYYMM, MM이 '00'이 들어가는 경우는 년,월 마감일경우)
     *           pCloseDD  : 마감일 | 마감주기 (Y)년마감   : 00
     *                                     (H)반기마감 : 1:전기, 2:후기
     *                                     (Q)분기마감 : 1,2,3,4
     *                                     (M)월마감   : 00
     *                                     (W)주마감   : 1,2,3,4,5
     *                                     (D)일마감   : 해당일(01~31)
     *           pWorkNo   : 작업번호
     *           pMgntNo   : 관리번호(Default : "0")
     *           pRtnKind  : DAY:마감일리턴, ARR:결과를배열로, null:마감여부 결과리턴
     *           pDualChkYN: 작업마감체크기(CUR) 선행마감까지 체크를 할것인가 여부 Y:체크함
     *           pCoCd     : 회사코드
     *
     * @return : 0     : 마감중
     *           1     : 미마감
     *           2     : 마감완료
     *           DNF   : Data Not Found
     *           null  : 파라메터 오류
     *           마감일 : 리턴구분이 "DAY" 일경우(YYYYMMDD)
     *           ArrayObj : 리턴구분이 "ARR" 일경우 (리턴코드,작업번호,작업명,CUR or PRE)
     *           리턴구분이 DAY,ARR이 아닌경우 선행마감이 안된경우 (P0:마감중,P1:미마감 리턴함)
     */
    await udc_cfJobCloseYN.cfJobCloseYN("CUR", ica_closeYm.getValue().trim(), "00"
                                                     , ACConstants.CLOSE_DEPRECIATION, "0", "", ""
                                                     , ed_coCd.getValue())
    .then(function (arrRtn) {
            scwin.isClose = arrRtn;
//             console.log("부모창 isClose : " + scwin.isClose);
        });
    if (scwin.isClose == "0") {
        await $c.gus.cfAlertMsg("마감중입니다.");
        return false;
    } else if (scwin.isClose == "2") {
        await $c.gus.cfAlertMsg("마감완료가 되었습니다.");
        return false;
    } else {
        return true;
    }
};


/**
 * 회사코드 팝업호출(UDC)
 */
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {
    //asis 소스
    // var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
    //     , ed_coCd.text, ed_coNm.value
    //     , pWinCloseTF, null, null, null, null
    //     , null, null, null, null, null);
    // // SET
    // if (rtnList != null) {
    //     if (rtnList[0] == "N/A") return;

    //     ed_coCd.setValue = rtnList[0]; // 코드
    //     ed_coNm.value = rtnList[5]; // 회사명
    //     ed_coCd.hidVal = rtnList[0]; // 히든값
    //     scwin.txtCoClsCd = rtnList[1]; // 회사구분
    // } else {
    //     ed_coCd.setValue = "";
    //     ed_coNm.value = "";
    //     ed_coCd.hidVal = "";
    //     scwin.txtCoClsCd = "";
    // }

    udc_comCode.cfCommonPopUp(scwin.udc_comCode_callBackFunc, ed_coCd.getValue(), ed_coNm.getValue(), pWinCloseTF, null
                            , null, null, null, null, null
                            , null, null, null, null, null
                            , null, null
    );    
};

/**
 * 회사코드 팝업 callBack
 */
scwin.udc_comCode_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_coCd.setValue(ret[0]);        // 코드
        ed_coNm.setValue(ret[5]);        // 회사명
        ed_coCd.hidVal = ret[0];         // 히든값
        scwin.txtCoClsCd = ret[1];       // 회사구분
    } else {
        ed_coCd.setValue("");            // 코드
        ed_coNm.setValue("");            // 회사명
        ed_coCd.hidVal   = "";           // 히든값
        scwin.txtCoClsCd = "";           // 회사구분
    }

    //TODO : 처음 로딩 시 한번만 처리(웹스퀘어 UDC 싱크....)
    if(scwin.first == 0) {
		// 자회사 회계 시스템
        if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
            scwin.isSubCompany = true;
        } else {
            scwin.isSubCompany = false;
        }
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }
    scwin.first++;
};


/**
 * 조회영역 onkeydown
 */
scwin.search_onkeydown = function (e) {
    if (e.keyCode == "13") {
        if(!$c.util.isEmpty(e.target.value)) {
            this.setValue(e.target.value);
            scwin.f_Retrieve();
        }
    }
};


/*##############################################################
 * UDC 이벤트
 *##############################################################*/
/**
 * 회사코드(조회) 팝업 호출
 */
scwin.udc_comCode_onclickEvent = function (e) {
    if(ed_coCd.hidVal != ed_coCd.getValue()) {
        ed_coNm.setValue("");
    }
    scwin.f_PopUpCompanyInfo('F');
};
scwin.udc_comCode_onviewchangeCodeEvent = function (info) {
    ed_coNm.setValue("");
    if(!$c.gus.cfIsNull(ed_coCd.getValue())) {
		scwin.f_PopUpCompanyInfo('T');
    }
};
